/**
 * @fileoverview Select (native) barrel.
 * @module module/Select
 */
import { default as razyui } from '../index.js';
import { SelectDef as DEF } from './Select.def.js';
import Select from './Select/index.js';

razyui.Select = Select;

if (razyui.JIT?.defineComponent) {
    razyui.JIT.defineComponent(DEF.name, DEF);
}

export async function registerElement() {
    const ce = await razyui.ce?.();
    ce?.registerFromDef?.(DEF, Select);
}

export default Select;

export const stylesheet = null;
