/**
 * @fileoverview Select (native) view setup.
 * @module module/Select/view
 */

import { CLS, PART } from './constants.js';

export function setupDOM(root) {
    root.addClass(CLS.ROOT);
    PART.ROOT.apply(root);

    root.find('.' + CLS.LABEL).each(el => {
        PART.LABEL.apply(el);
    });
    root.find('.' + CLS.DESCRIPTION).each(el => {
        PART.DESCRIPTION.apply(el);
    });
    root.find('.' + CLS.WRAPPER).each(el => {
        PART.WRAPPER.apply(el);
    });
    root.find('.' + CLS.FIELD).each(el => {
        PART.FIELD.apply(el);
    });
    root.find('.' + CLS.CHEVRON).each(el => {
        PART.CHEVRON.apply(el);
    });

    return {};
}
